#include <bits/stdc++.h>
using namespace std;
struct Edge{
	int u,v;
}edge[100005];
int t,n,p[100005];
bool found,use[100005];
vector<int> g[100005];
void dfs(int x){
	if(found)
		return;
	if(x>n){
		for(int i=1;i<n;i++)
			if(p[edge[i].u]+p[edge[i].v]>n+1)
				return;
		found=true;
		for(int i=1;i<=n;i++)
			printf("%d ",p[i]);
		printf("\n");
		return;
	}
	for(int i=1;i<=n;i++)
		if(!use[i]){
			use[i]=1,p[x]=i;
			dfs(x+1);
			use[i]=0;
		}
}
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        bool flag1=1,flag2=1;
        for(int i=1;i<n;i++){
            int u,v;
            scanf("%d%d",&u,&v);
            edge[i]={u,v};
            if(u!=1 || v!=i+1)
                flag1=0;
            if(u!=i || v!=i+1)
                flag2=0;
        }
        if(flag1){
            for(int i=1;i<=n;i++)
                printf("%d ",i);
            printf("\n");
        }else if(flag2){
            int s1=n,s2=1;
            for(int i=1;i<=n;i++)
                if(i%2)
                    printf("%d ",s1--);
                else
                    printf("%d ",s2++);
            printf("\n");
        }else{
        	found=false;
            dfs(1);
        }
    }
    return 0;
}
